INSERT INTO `news` (`id`, `title`, `text`, `image`, `position`, `banner_id`) VALUES
(1, 'Масштабное снижение цен!', 'Скидки до 50% на самые востребованные категории кабельной продукции и оборудования. Успейте зафиксировать выгоду для ваших проектов.', 'sales-banner.png', 2, 1),
(2, 'Встречайте новый бренд — Cabeus!', ' Мировой стандарт качества в нашем каталоге. Полный ассортимент структурированных кабельных систем (СКС) уже доступен для заказа.', 'cabeus-banner.png', 1, 1),
(3, 'Персональные предложения и скидки', 'Подпишитесь на нашу информационную рассылку. Получайте только актуальные прайс-листы, закрытые распродажи и аналитику рынка первыми.', 'personal-banner.jpg\r\n', 127, 1),
(4, 'Время обновить освещение?', 'От бытовых лампочек до промышленного и уличного светодиодного оборудования. Надежные решения с гарантией высокой энергоэффективности.', 'light.png', 127, 1),
(5, 'Выгода для постоянных клиентов', 'Зарегистрируйтесь на сайте и получите дополнительную скидку 10% на первый заказ. Управляйте покупками через удобный личный кабинет.', 'email-banner.jpg', 127, 1);
